select (select count(*) from properties where lower(properties.owner) = lower($1))::int as count_parcels, (select count(*) from womps where lower(womps.author) = lower($1))::int as count_womps, (select count(*) from collections where lower(collections.owner) = lower($1))::int as count_collections, (select count(*)
                                                                                                                                                                                                                                                                                                            from parcel_events
                                                                                                                                                                                                                                                                                                            where lower(parcel_events.author) = lower($1))::int as count_events, (select count(*) from wearables where lower(wearables.author) = lower($1)) ::int as count_wearables;
